import json

with open("/root/books/webapp/books.json", "r", encoding="utf-8") as f:
    books = json.load(f)

updates = {
127: {
    0: "Мы по умолчанию выражаем любовь так, как хотим её получать сами. Но партнёр может «слышать» совершенно другой язык. Любить — это не то что ты делаешь. Это то что другой человек получает и чувствует. Спроси партнёра напрямую: «Когда ты чувствуешь что я тебя люблю — что именно происходит в этот момент?» Ответ откроет его язык. Часто оказывается что мы годами делаем что-то из любви — но в форме которую другой не слышит. Это не недостаток любви — это ошибка перевода.",
    1: "Многие из нас выросли в семьях где любовь подразумевалась но не произносилась. Мы перенесли это в свои отношения. Но «она знает» — не замена «я скажу». Слова имеют силу, даже если кажутся банальными. Попробуй в течение недели говорить партнёру одно конкретное наблюдение в день — не общее «я тебя люблю», а конкретное: «мне нравится как ты...», «я ценю что ты...». Конкретные слова попадают точнее. И они запоминаются иначе чем привычные фразы.",
    2: "В эпоху смартфонов время качества стало дефицитом даже между людьми которые живут вместе. Два человека рядом, но каждый в своём экране — это одиночество вдвоём. Полное присутствие — это редкий подарок. Попробуй: 20 минут без телефона и без фонового телевизора — только разговор или совместное занятие. Не потому что так надо — а потому что именно в эти минуты партнёр с языком «время качества» чувствует что он важен. Это дешевле любого подарка.",
    3: "Люди которые сами не ценят подарки — часто не понимают зачем их дарить. Им кажется это формальностью. Но для партнёра с этим языком забытый день рождения — это «ты не думаешь обо мне». Символы имеют вес. Подарок не должен быть дорогим — он должен говорить «я думал о тебе когда тебя не было рядом». Билет на мероприятие которое он давно хотел посетить. Книга автора которого он упомянул. Маленькое но точное — мощнее большого но безликого.",
    4: "Многие люди буквально не умеют принимать слова — они верят только поступкам. «Покажи, не говори» — их принцип. Для них «я занят» звучит как «ты мне не важна». Подумай: что конкретно ты мог бы сделать для партнёра на этой неделе — не потому что нужно, а чтобы облегчить его жизнь? Приготовить ужин когда он устал. Сделать то что он давно откладывал. Это не обязанность — это выбор который говорит больше слов.",
    5: "В некоторых культурах прикосновения — норма, в других — табу. Люди выросшие в «бесконтактных» семьях часто не умеют использовать этот язык — и не дают его тем, кто в нём нуждается. Это не холодность — это незнание. Начни с малого: взять за руку в кинотеатре, обнять без повода когда проходишь мимо, прикоснуться к плечу во время разговора. Для человека с этим языком каждое такое прикосновение — это наполнение резервуара любви. Разрыв физического контакта разрушает связь быстрее чем ссоры.",
    6: "Мы редко слышим прямые запросы — они закодированы в претензиях и намёках. Но если научиться читать эти сигналы — можно дать партнёру именно то, что ему нужно, а не то что кажется логичным нам. Понаблюдай: на что партнёр жалуется чаще всего? «Ты никогда меня не слушаешь» — возможно язык время качества. «Ты давно мне ничего не говорил хорошего» — слова поощрения. Претензия — это искажённая просьба. Услышь просьбу.",
    7: "Романтическая культура продаёт любовь как чувство которое либо есть либо нет. Но отношения которые длятся — это не те где химия не прошла. Это те где люди сознательно выбирают любить каждый день. Выбор любить — это не отсутствие чувства. Это решение действовать в пользу отношений когда чувство ослабло. Иногда действие возвращает чувство. Всегда — оно укрепляет связь которая в конечном счёте важнее острой влюблённости.",
    8: "Многие кризисы в отношениях — это просто давно пустые резервуары с обеих сторон. Люди не перестали любить — они просто перестали говорить на нужном языке. Иногда достаточно недели целенаправленного внимания чтобы изменить всё. Если чувствуешь что отношения охладели — попробуй в течение недели каждый день целенаправленно наполнять резервуар партнёра его языком любви. Один раз в день. Семь дней. Это очень мало для усилий — и очень много для результата.",
    9: "Мы любим детей так как умеем — но умеем мы говорить только на собственном языке. Ребёнок с другим языком чувствует себя нелюбимым несмотря на все усилия. Научиться говорить на языке ребёнка — одна из самых важных родительских задач. Наблюдай: как ребёнок выражает любовь к тебе? Через объятия, слова, подарки из листочков, помощь или когда тянет тебя играть? Скорее всего это и есть его язык. Ответь ему тем же — и связь укрепится.",
},
229: {
    0: "Если любовь — это действие, то её можно практиковать даже когда не чувствуешь вдохновения. И можно проверить — действительно ли то что называешь любовью, является ею по своим проявлениям. Задай себе честный вопрос: что я сделал за последнюю неделю что было актом любви — а не привычкой или обязанностью? Любовь как действие требует выбора и намерения. Это сложнее чем просто чувствовать — и ценнее. Потому что то что мы намеренно делаем — это то кем мы становимся.",
    1: "Неумение любить — это не личная слабость, это пробел в образовании. Это значит что этому можно учиться намеренно: через книги, практику, терапию, наблюдение за здоровыми отношениями. Большинство людей учились «любви» наблюдая за родителями — которые сами не знали как. Это не вина и не приговор. Это означает что у тебя нет части пазла — и её можно найти. Намеренное обучение любви требует смирения и решимости. Но результат — это другое качество всех твоих связей.",
    2: "Настоящая любовь требует честности даже когда это неудобно. Кто говорит правду из уважения — строит отношения на реальности. Кто лжёт из страха или удобства — строит отношения на иллюзии. Посмотри на свои текущие отношения: есть ли что-то что ты не говоришь — из страха реакции или нежелания создавать конфликт? Это место где честность нужна больше всего. Не жестокая честность — честность из уважения к другому и к реальности которую вы разделяете.",
    3: "Работа над отношением к себе — это не нарциссизм. Это строительство фундамента на котором только и возможна настоящая любовь к другому. Без этого фундамента отношения строятся на нужде а не на выборе. Человек который не умеет любить себя приходит в отношения с дефицитом который невозможно заполнить извне. Любое количество любви партнёра будет утекать. Работа над собственным фундаментом — самая важная работа которую ты можешь сделать для своих отношений.",
    4: "Культурное программирование влияет на способность к близости. Осознать что именно тебе внушали о любви, уязвимости и отношениях — первый шаг к возможности любить иначе. Запиши: что тебе говорили о любви в детстве — прямо или через поведение родителей? Что говорила культура вокруг? Какие из этих посланий ты несёшь до сих пор — и хочешь ли ты их нести? Осознание не равно освобождению. Но без осознания освобождение невозможно.",
    5: "Разочарование в отношениях часто происходит когда влюблённость проходит а работа любить — не начинается. Понять что любовь требует усилий — значит перейти от пассивного ожидания к активному строительству. Какое конкретное усилие ты делаешь для своих отношений — не то что само случается, а то что ты выбираешь? Регулярный разговор о том как дела у каждого. Совместное занятие которое оба ждут. Момент внимания без повода. Это и есть работа любить.",
    6: "Любовь не причиняет боль намеренно. Когда боль систематически причиняется под именем любви — это не любовь. Называть это правильно — важно для того чтобы понять что происходит и что делать. Если в твоих отношениях есть регулярная боль которую тебе объясняют любовью — остановись. Боль в любви бывает — от роста, от честности, от трудных разговоров. Но намеренная и систематическая боль — это другое. Умение называть это правильно — первый шаг к изменению.",
    7: "Видеть в любви что-то большее чем химию и выгоду — меняет отношение к ней. Это делает её практикой которую стоит развивать, а не просто состоянием которое либо есть либо нет. Попробуй относиться к своей способности любить как к мышце. Что тренирует эту мышцу? Внимательность к другому. Готовность к уязвимости. Практика прощения. Выбор быть рядом когда это трудно. Регулярные тренировки меняют способность — в любом навыке.",
    8: "Полноценная любовная жизнь — это не только пара. Это сеть связей: глубокие дружбы, принадлежность к сообществу, забота о незнакомых. Кто строит только одну связь — строит хрупкую систему. Посмотри на свою сеть связей. Есть ли у тебя отношения где ты можешь быть честным и уязвимым — кроме романтического партнёра? Перегрузка одного человека всеми эмоциональными потребностями создаёт давление которое разрушает даже сильные пары. Разнообразие связей — устойчивость системы.",
    9: "Разговоры о любви, близости, уязвимости — это не слабость и не сентиментальность. Это строительство культуры в которой люди умеют создавать настоящие связи. Начать этот разговор — значит что-то изменить. Кто из людей в твоём окружении говорит о любви, близости и отношениях честно — не поверхностно? Больше времени с такими людьми меняет твой внутренний разговор об этих темах. Мы становимся похожи на тех с кем общаемся — и это работает в пользу.",
},
242: {
    0: "Знать свой тип привязанности — значит понять почему ты делаешь то что делаешь в отношениях. Это не приговор — это карта. С картой можно строить маршрут. Определи свой тип: тревожный, избегающий или безопасный. Тревожный постоянно ищет подтверждения. Избегающий отступает при сближении. Безопасный умеет быть рядом без слияния и в одиночестве без паники. Зная свой тип — ты начинаешь замечать его проявления в реальном времени. Это первый шаг к выбору другой реакции.",
    1: "Понять что паттерн отношений определяется типами привязанности а не личными недостатками — снимает вину и открывает путь к изменению. Это про систему а не про плохих людей. Если ты тревожный — ты не «слишком прилипчивый». Если избегающий — ты не «холодный эгоист». Это паттерны сформированные в детстве когда у тебя не было выбора. Сейчас выбор есть. Понимание паттерна — не оправдание ему. Это точка откуда начинается изменение.",
    2: "Тип привязанности не фиксирован навсегда. Он меняется через опыт безопасных отношений — с партнёром, с терапевтом, с другом. Движение в сторону безопасности возможно в любом возрасте. Что сейчас в твоей жизни создаёт опыт безопасной привязанности? Человек который реагирует на твои потребности без осуждения. Отношения где можно быть уязвимым без наказания. Каждый такой опыт — это нейронный след который постепенно переписывает старый паттерн.",
    3: "Понять что за холодностью партнёра стоит страх а не безразличие — меняет всю интерпретацию его поведения. Это не делает боль меньше — но даёт другую точку для диалога. Когда избегающий партнёр отступает — его мозг сигнализирует об опасности сближения. Не о нежелании быть с тобой. Атака в этот момент усиливает его страх. Пространство и спокойствие — дают ему возможность вернуться. Это требует огромного терпения. Но это работает.",
    4: "Когда ты делаешь что-то что должно привлечь человека — но на деле отталкивает его — это протестное поведение. Осознать это в моменте очень трудно. Но именно это осознание разрывает цикл. Следующий раз когда почувствуешь импульс написать двадцатое сообщение без ответа или устроить сцену ради реакции — остановись. Спроси себя: я сейчас делаю это чтобы получить связь — или это оттолкнёт ещё сильнее? Пауза меняет результат.",
    5: "Если тебя постоянно притягивают нестабильные или недоступные люди — это не судьба и не тип. Это привязанность ищет знакомого. Осознание этого — первый шаг к выбору по-другому. Нестабильность и недоступность создают ту же нейрохимию что и детский опыт непредсказуемых отношений. Это знакомо — а знакомое кажется правильным. Когда кто-то безопасный и стабильный кажется «скучным» — это сигнал от привязанности. Не от сердца.",
    6: "Нуждаться в другом человеке — не слабость. Это биология. Стыдиться этой потребности и подавлять её — создаёт либо тревогу либо избегание. Принять что нам нужны люди — освобождает. Где в твоей жизни ты подавляешь потребность в близости — из страха показаться слабым или нуждающимся? Именно там стоит начать быть честнее. Не потому что это легко — а потому что подавление не исчезает. Оно выходит через другие каналы — тревогу, раздражение, дистанцию.",
    7: "Говорить о потребностях прямо — труднее чем кажется. Это требует уязвимости и доверия. Но это единственный путь к тому чтобы потребности были удовлетворены а не угаданы. Попробуй заменить «ты никогда не...» на «мне нужно...». Первое — обвинение. Второе — информация. Никто не умеет читать мысли. Даже самый внимательный партнёр не знает точно что тебе нужно если ты не сказал. Прямая коммуникация потребностей — самое любящее что ты можешь сделать для отношений.",
    8: "Мы часто думаем что нужно больше работать над отношениями. Иногда правда в том что партнёр системно не может дать то что нам нужно — и никакая работа этого не изменит. Есть разница между отношениями которые требуют работы — и отношениями в которых фундаментальная несовместимость. Первые становятся лучше через усилие. Вторые остаются болезненными несмотря на любое усилие. Честный ответ на этот вопрос — самый важный и самый трудный.",
    9: "Когда идея становится вирусной — это сигнал что она попала в реальную массовую боль. Теория привязанности стала вирусной потому что люди наконец нашли язык для того что всегда чувствовали но не могли назвать. Если теория привязанности описывает твои отношения — ты не одинок в этом паттерне. Миллионы людей проживают те же циклы. Это не делает боль меньше — но снимает стыд. А отсутствие стыда — это условие при котором возможна настоящая работа над собой.",
},
243: {
    0: "Закрытость защищает от боли отвержения — но также закрывает путь к настоящей связи. Это выбор который каждый делает сам: безопасность или близость. Одновременно — нельзя. Есть ли в твоей жизни человек которому ты позволяешь видеть тебя настоящего — со страхами, сомнениями, провалами? Не один? Это сигнал. Уязвимость — не значит рассказывать всё всем. Это значит позволить хотя бы одному человеку видеть тебя без маски. Это единственный путь к не-одиночеству.",
    1: "Что-то что ты несёшь в тайне из стыда — держит тебя в изоляции. Назвать это доверенному человеку — не значит потерять контроль. Это значит перестать нести это в одиночестве. Стыд процветает в темноте — и умирает когда его называют. Это не метафора. Нейробиологически — называние стыда другому человеку и получение сочувственного ответа снижает его физиологическую силу. Найди человека которому доверяешь — и попробуй. Не обязательно большое. Начни с малого.",
    2: "Перфекционизм обещает защиту от боли — но на деле создаёт тревогу и изоляцию. Принять что ты достаточно хорош уже сейчас — не значит перестать расти. Это значит перестать наказывать себя за несовершенство. Где в твоей жизни перфекционизм стоит тебе больше чем даёт? Возможно ты откладываешь проект пока он не станет идеальным. Не начинаешь отношения пока сам не станешь лучше. Не показываешь работу пока она не будет безупречной. Совершенство — враг настоящего.",
    3: "Хроническое ощущение недостаточности — не мотивация к росту. Это источник тревоги который никогда не насыщается. Настоящий рост идёт из позиции достаточности а не дефицита. Попробуй осознанно: что уже есть в твоей жизни что достаточно? Не идеально — достаточно. Здоровье которое работает. Отношения которые существуют. Работа которая кормит. Начни с достаточного — и замечай как из этого места риск и рост становятся возможными а не пугающими.",
    4: "Группа которая принимает тебя только когда ты соответствуешь — не даёт настоящего чувства принадлежности. Оно приходит только там где тебя принимают настоящего. Посмотри на своё окружение: есть ли места где ты можешь быть собой — с неудобными мнениями, странными увлечениями, плохими днями? Если нет — это не принадлежность, это членство по условиям. Поиск места где тебя принимают настоящим — одна из важнейших задач взрослого человека.",
    5: "Благодарность как практика — не наивность и не отрицание проблем. Это тренировка внимания на то что есть а не на то чего нет. Это меняет нейрохимию мозга со временем. Попробуй: в конце каждого дня называть три конкретные вещи за которые благодарен. Не «здоровье и семья» — конкретные: «разговор с другом который меня рассмешил», «кофе который был именно таким». Конкретность важна — она требует реального внимания. Именно это внимание и является практикой.",
    6: "Творческое выражение — не роскошь для особых людей. Это потребность. Кто не находит для него места — со временем ощущает пустоту которую не могут заполнить достижения. Что ты создаёшь — не для результата, не для оценки, а потому что это ты? Рисование, музыка, готовка как творчество, сад, текст который никто не прочитает. Это может быть что угодно. Важно что есть что-то где ты выражаешь себя — а не только выполняешь функции.",
    7: "Сравнение с другими всегда нечестное — мы видим их лучшее и сравниваем со своим средним или худшим. Осознать момент когда ты сравниваешь — и выйти из него — важный навык. Следующий раз когда поймаешь себя на сравнении — спроси: я сравниваю их Instagram с моей кухней. Их профессиональный результат с моим процессом. Это не реальное сравнение. Единственное полезное сравнение — ты сегодня с тобой вчера.",
    8: "Разрешить себе отдыхать без вины — это не слабость. Это признание что ты человек а не машина. Хроническое игнорирование потребности в отдыхе приводит к выгоранию которое стоит дороже любого перерыва. Что происходит когда ты пытаешься отдохнуть? Есть ли внутренний голос который говорит что надо ещё что-то сделать? Это не совесть — это программа. Она была полезной когда-то. Сейчас она мешает восстановлению которое необходимо для устойчивой продуктивности.",
    9: "Быть собой — это не пассивное состояние. Это активный выбор который делается каждый день в каждой ситуации. Особенно в тех где быть собой — неудобно или рискованно. Сегодня была ли ситуация где ты смолчал, согласился или стал собой «удобным» — вместо того чтобы сказать что думаешь? Это не осуждение — это наблюдение. Чем больше таких моментов — тем дальше от себя. Аутентичность требует тренировки. Каждый маленький момент честности — это её укрепление.",
},
244: {
    0: "Большая часть того что кажется общением — это обмен ролями и скрытыми посланиями. Осознать это не значит стать циником. Это значит видеть реальность отношений яснее. Сегодня в разговоре с кем-то важным — попробуй наблюдать: есть ли скрытые послания под словами? Что ты реально просишь когда говоришь то что говоришь? Что просит другой? Часто под «ты опять опоздал» прячется «я хочу чувствовать что ты меня ценишь». Увидеть этот слой — значит иметь возможность ответить на реальный запрос.",
    1: "Осознать из какого состояния ты сейчас говоришь — и из какого отвечает собеседник — даёт огромную ясность. Многие конфликты это просто Ребёнок против Родителя а не реальное разногласие. Попробуй: в следующем конфликте — прежде чем ответить, спроси себя: «из какого состояния я сейчас?» Если это Ребёнок (обиженный, импульсивный) или Родитель (поучающий, осуждающий) — пауза. Переключиться во Взрослого можно намеренно. Это меняет исход разговора.",
    2: "Когда кто-то постоянно отвергает твои предложения помочь — возможно цель не в помощи. Понять что игра идёт — значит выйти из неё. Не давать советов тому кто их не хочет принять. Когда ты замечаешь цикл «я советую — ты отвергаешь» — попробуй полностью выйти из роли советчика. Не давай совета. Просто скажи: «понимаю, это тяжело». И молчи. Это выход из игры. Иногда это разрушает паттерн — и человек действительно просит о настоящей помощи.",
    3: "Любое внимание — это поглаживание. Люди которые не получают позитивного внимания — неосознанно провоцируют негативное. Это объясняет многое в поведении людей которые «всё время создают проблемы». Посмотри на человека в твоём окружении который постоянно делает что-то раздражающее. Сколько позитивного внимания он получает? Иногда увеличение позитивного внимания — уменьшает раздражающее поведение. Потому что потребность удовлетворяется без игры.",
    4: "Если ты регулярно оказываешься в одной из трёх ролей — ты в треугольнике. Выход — осознать роль и отказаться от неё. Не спасать тех кто не просил. Не жертвовать там где можно действовать. Какая роль твоя привычная? Спасатель берётся помочь без просьбы. Жертва всегда страдает от обстоятельств. Преследователь критикует и давит. Выйти из треугольника — значит отказаться от своей роли. Даже если другие продолжают играть свои.",
    5: "Осознать свой жизненный сценарий — значит получить возможность его переписать. Не все послания из детства правда. Часть из них — ошибки усталых или испуганных людей. Какое послание о себе ты получил в детстве — и несёшь до сих пор? «Ты неудачник», «ты не заслуживаешь хорошего», «ты слишком много хочешь». Это не факты — это мнения людей которые сами были ограничены. Ты можешь выбрать другой сценарий. Это требует работы — но это возможно.",
    6: "Если близости нет — возможно дело не в людях а в том что оба играют роли вместо того чтобы быть в контакте. Прекратить игру страшно. Но только так возникает настоящая связь. Есть ли в твоих отношениях момент когда роли прекращаются и ты просто ты — а другой просто он? Без повестки, без ролей, без игр? Если нет — это не значит что люди не хотят близости. Это значит что никто не решился первым снять маску. Кто-то должен быть первым.",
    7: "Разница между «ты всегда» и «сейчас я чувствую» — огромная. Первое атакует человека. Второе говорит о ситуации. Эта простая замена меняет качество конфликта. В следующем конфликте попробуй заменить все «ты» на «я». «Ты не слушаешь» → «я чувствую что меня не слышат». «Ты всегда опаздываешь» → «когда ты опаздываешь мне тяжело». Это звучит странно поначалу. Но это буквально меняет нейронную реакцию собеседника — с защиты на слушание.",
    8: "В любом повторяющемся конфликте или паттерне — осознание своей роли важнее чем анализ роли другого. Ты можешь изменить только свою часть игры. Есть ли в твоей жизни конфликт который повторяется с разными людьми? Это не совпадение — это твой вклад в паттерн. Не вина — вклад. Найти свою роль в повторяющемся конфликте — значит найти единственную точку где у тебя есть реальная власть изменить ситуацию.",
    9: "Классические книги о психологии человека остаются актуальными потому что человеческая природа не меняется за десятилетия. Базовые потребности в признании, близости и безопасности — те же что 60 лет назад. Что тебе нужно прямо сейчас — признание, близость или безопасность? Часто за любым напряжением в отношениях стоит одна из этих трёх потребностей. Назвать её — уже половина решения. Потому что когда ты знаешь что ищешь — ты можешь попросить об этом прямо.",
},
245: {
    0: "Созависимое поведение часто хвалят: «ты такой самоотверженный, всегда помогаешь другим». Но за этим скрывается потеря себя. Отличить заботу от созависимости — важный вопрос. Забота идёт из избытка — когда у тебя есть ресурс и ты делишься им свободно. Созависимость идёт из страха — когда ты помогаешь чтобы избежать тревоги или получить одобрение. Задай себе честный вопрос: я помогаю потому что хочу — или потому что не могу не помочь?",
    1: "Потребность контролировать других — это сигнал тревоги и беспомощности. Отпустить контроль страшно. Но именно в этом отпускании — и собственная свобода и уважение к другому. Где в твоей жизни ты пытаешься контролировать то что не в твоей власти? Чьи решения, чьё поведение, чей выбор ты пытаешься направлять — тратя на это силы? Каждый рубль энергии потраченный на контроль другого — это рубль отнятый от работы с собой.",
    2: "Спасать человека от последствий его выборов — значит лишать его возможности учиться и меняться. Позволить последствиям случиться — это иногда самое любящее что можно сделать. Есть ли в твоей жизни человек которого ты постоянно спасаешь? Который снова оказывается в той же ситуации несмотря на твою помощь? Задай себе вопрос: моя помощь даёт ему инструменты для изменения — или убирает давление которое могло бы к этому привести?",
    3: "Игнорирование собственных потребностей не делает тебя лучшим помощником — оно делает тебя истощённым и обиженным. Право на свои потребности — базовое. Когда ты последний раз делал что-то только для себя — не из чувства вины, не потому что заслужил, не «наконец-то могу» — а просто потому что это нужно тебе? Если вспомнить сложно — это информация. Потребности не исчезают когда их игнорируют. Они накапливаются и выходят через обиду или болезнь.",
    4: "Граница — это не стена и не наказание. Это информация о том что для тебя приемлемо. Устанавливая границы ты не отвергаешь человека — ты честно говоришь что тебе нужно. Что для тебя неприемлемо в текущих отношениях — но ты молчишь об этом? Молчание не сохраняет отношения — оно накапливает обиду. Граница сказанная из уважения — это уважение и к себе и к другому. Человеку которому важны отношения с тобой — важно знать твои границы.",
    5: "Принять что ты не можешь изменить другого человека — одно из самых освобождающих признаний. Не потому что ты сдаёшься. А потому что признаёшь реальность: каждый меняется сам. Сколько энергии ты тратишь на попытки изменить поведение конкретного человека? Этот же объём энергии направленный на себя — что он мог бы изменить? Принятие ограниченности твоего влияния на других — не пораженчество. Это освобождение ресурсов для того где влияние реальное.",
    6: "Понять откуда пришёл паттерн — не значит оправдать его. Это значит увидеть что это выученное поведение а не твоя природа. Выученное можно разучить. Какое поведение в отношениях ты воспроизводишь — и понимаешь откуда оно? Видел ли ты это в семье где вырос? Назвать источник не значит снять ответственность. Напротив — когда знаешь откуда паттерн, видишь что это не ты. И что у тебя есть выбор которого не было у тебя в детстве.",
    7: "Структурированные программы восстановления работают потому что они создают внешние точки опоры когда внутренних недостаточно. Просить о помощи и следовать структуре — не слабость. Есть ли в твоей жизни область где внешняя структура могла бы помочь — группа поддержки, регулярная терапия, обязательства перед другим человеком? Мы переоцениваем силу воли и недооцениваем ценность внешних опор. Умные люди используют внешние структуры — не вместо себя, а в дополнение к себе.",
    8: "Изменение глубоких паттернов — не событие а процесс. Ожидать мгновенного результата — значит настраивать себя на разочарование. Маленькие ежедневные шаги меняют больше чем одно большое решение. Что маленькое ты можешь делать каждый день — что со временем изменит паттерн? Не большой шаг — маленький. Один разговор о своих потребностях в неделю. Одно «нет» в день. Одна минута наблюдения за собственной тревогой без немедленного действия. Маленькое и регулярное.",
    9: "Правильная книга в правильный момент может изменить всё. Это не преувеличение. Слова которые называют твою боль и показывают выход — это мощнейший инструмент изменения. Есть ли книга которая изменила твой взгляд на что-то важное? Что именно она сделала — дала язык для того что ты чувствовал? Показала что ты не одинок? Открыла возможность которую ты не видел? Передай её кому-то кому она нужна. Правильная книга попавшая к нужному человеку — это подарок.",
},
246: {
    0: "Большинство конфликтов в близких отношениях — это замаскированные вопросы о принадлежности и ценности. Научиться слышать этот вопрос под словами — один из самых ценных навыков в отношениях. В следующий раз когда партнёр нападает или отдаляется — попробуй не реагировать на слова. Спроси себя: что он сейчас проверяет? «Ты важен для меня?» или «Ты никуда не уйдёшь?» Ответ на этот невысказанный вопрос — важнее ответа на произнесённые слова.",
    1: "Повторяющийся конфликт в паре — это обычно один и тот же танец а не новая проблема. Увидеть паттерн важнее чем победить в конкретной ссоре. Есть ли в твоих отношениях конфликт который возникает снова и снова — с разными поводами но одной структурой? Один нападает — другой закрывается. Один требует — другой уходит. Увидеть танец — значит получить возможность выйти из него. Нельзя изменить танец если не видишь что танцуешь.",
    2: "Быть физически рядом — недостаточно. Эмоциональная доступность требует внимания, отзывчивости и присутствия. Это можно развивать осознанно. Что означает «быть эмоционально доступным» конкретно для тебя? Убрать телефон когда партнёр говорит о чём-то важном. Спросить как дела — и реально слушать ответ. Отложить свою повестку когда у партнёра трудный момент. Это навык который требует практики — и который полностью меняет качество присутствия в отношениях.",
    3: "Физический контакт с близкими — базовая биологическая потребность. Пары которые перестают прикасаться друг к другу — разрушают связь не только эмоционально но и физиологически. Когда ты последний раз прикасался к партнёру без сексуального намерения — просто как выражение близости? Объятие утром. Рука на плече. Это поддерживает окситоцин — гормон связи — на уровне который буквально влияет на качество отношений. Маленький физический контакт каждый день — это регулярный вклад в счёт близости.",
    4: "Формальное прощение без понимания — не исцеляет. Оно только откладывает боль. Настоящее прощение требует что один рассказал о своей боли а другой по-настоящему услышал. Есть ли что-то в твоих отношениях что официально «прощено» — но реально не прожито? Место где боль была свернула направо вместо того чтобы пройти насквозь? Настоящее прощение требует разговора который страшно начать. Но именно этот разговор освобождает от того что продолжает влиять.",
    5: "За большинством конфликтов в близких отношениях — страх а не злость. Увидеть страх за атакой партнёра — меняет реакцию. Злость хочет сдачи. Страх хочет успокоения. Когда партнёр атакует — спроси себя: чего он боится прямо сейчас? Быть брошенным? Оказаться ненужным? Потерять контроль? Ответ на страх — это не согласие с атакой. Это успокоение: «я здесь, никуда не ухожу». Это разрывает цикл которого не разрывает ответная атака.",
    6: "Смена формы разговора — с обвинений на уязвимость — требует огромного мужества. Но именно она создаёт возможность для настоящего контакта. Попробуй: вместо «ты никогда не...» — «мне страшно когда...». Вместо «ты всегда...» — «мне нужно...». Это звучит незащищённо. Именно поэтому это работает — потому что на уязвимость невозможно атаковать без разрушения чего-то важного внутри атакующего. Уязвимость разоружает.",
    7: "Физическая близость и эмоциональная связь — не отдельные измерения. Они взаимосвязаны. Работа над эмоциональной связью влияет на физическую — и наоборот. Если в твоих отношениях одна из этих сфер угасает — посмотри на другую. Часто проблемы физической близости являются симптомом эмоциональной дистанции — и наоборот. Работа с одним влияет на другое. С какой стороны легче начать — с этого и начни.",
    8: "Терапия для пар работает — если оба готовы к честной работе. Обращение за профессиональной помощью в отношениях — не признак провала. Это признак того что отношения важны. Ждать обращения к специалисту пока ситуация не стала критической — распространённая ошибка. Терапия для пар эффективнее как профилактика и развитие чем как скорая помощь в кризисе. Если есть повторяющийся паттерн который сами не можете изменить — это повод обратиться. Не ждать катастрофы.",
    9: "Любовь требует активного поддержания — как любой живой организм. Пассивное ожидание что она сохранится сама — это стратегия потери. Осознанное строительство — стратегия сохранения. Что ты делаешь намеренно для поддержания связи с партнёром? Не то что само происходит — а то что ты выбираешь. Регулярный ритуал только для вас двоих. Вопрос который ты задаёшь потому что тебе интересно — а не из вежливости. Намерение создаёт результат который пассивность не создаёт.",
},
247: {
    0: "Понимание биохимии влюблённости не убивает романтику — оно объясняет её. И даёт важный инсайт: острая влюблённость всегда проходит. Это не конец любви — это её переход в другую форму. Если ты сейчас в состоянии острой влюблённости — наслаждайся ею и одновременно не принимай в этом состоянии необратимых решений. Если влюблённость прошла — не паникуй. Это нормально и это не конец. Следующий вопрос: что вы строите на месте химии — реальную близость или пустоту?",
    1: "Понимание что эти три системы независимы объясняет многие «необъяснимые» переживания в отношениях. Это снимает часть вины и даёт более трезвый взгляд на сложность человеческой любви. Три системы — влечение, романтическая любовь и привязанность — могут быть направлены к разным людям одновременно. Это не делает тебя плохим человеком. Это делает тебя человеком. Знание о независимости систем помогает понять что происходит — и принять осознанное решение о том что с этим делать.",
    2: "Знание биологических импульсов не оправдывает следование им. Но снимает часть вины и даёт реалистичный взгляд на то с чем люди работают когда строят долгосрочные отношения. Это выбор — непростой. Долгосрочная верность — это не отсутствие биологических импульсов. Это решение принимаемое снова и снова вопреки им. Это требует не только желания но и структуры: совместных ритуалов, эмоциональной близости, физического контакта — которые поддерживают привязанность сильнее чем новизна.",
    3: "Понимание своего темперамента и темперамента партнёра помогает объяснить притяжение и конфликты. Некоторые различия дополняют друг друга. Другие создают хроническое трение. Что тебя притягивает в партнёре — и что создаёт наибольшее трение? Иногда это одно и то же качество. Человек который кажется «таким живым» в начале — может казаться «хаотичным» позже. Понимание этого не решает проблему — но даёт возможность работать с ней осознанно а не из разочарования.",
    4: "Серьёзность боли от расставания — не слабость и не преувеличение. Это биологически обоснованная реакция. Отнестись к этому как к реальному кризису — а не требовать от себя «взять себя в руки» — правильнее. Если ты переживаешь расставание — дай себе реальное время и реальные ресурсы для восстановления. Это не нытьё — это физиология. Социальная поддержка, движение тела, смена обстановки — работают биохимически. Требовать от себя быстрого восстановления — значит не понимать масштаб происходящего.",
    5: "Угасание остроты влюблённости после первых лет — не конец романтической любви. Это переход. Пары которые понимают это — не ищут нового партнёра а работают над поддержанием связи. Что создаёт дофаминовый эффект новизны в долгосрочных отношениях? Совместные новые опыты — путешествие, навык, приключение. Разговоры о незнакомых темах. Изменение привычных ритуалов. Новизна не требует нового партнёра — она требует намеренного выхода за пределы привычного.",
    6: "Инвестиция в близкие отношения — это инвестиция в здоровье и долголетие буквально. Не метафорически. Одиночество — медицинская проблема а не просто дискомфорт. Посмотри на свои связи: есть ли у тебя хотя бы один человек с которым ты в настоящем контакте — не поверхностном, а реальном? Если нет — это не личная неудача, это дефицит который стоит исправить с той же серьёзностью с которой ты бы исправлял дефицит сна или питания. Близость — физиологическая потребность.",
    7: "Технологии меняют доступ — но не природу. Приложения для знакомств дают больше вариантов но не гарантируют лучший выбор. Химия первой встречи остаётся определяющей. Бесконечный выбор в приложениях создаёт парадокс: чем больше вариантов, тем сложнее сделать выбор и тем легче продолжать искать «лучшее». Если ты чувствуешь что застрял в бесконечном поиске — возможно проблема не в качестве людей в приложении, а в самом процессе потребительского выбора партнёра.",
    8: "Ревность — не слабость и не патология если она не разрушительна. Это сигнал о важности отношений. Вопрос в том как с ней обращаться — подавлять, проявлять разрушительно или использовать как информацию. Когда ты чувствуешь ревность — что именно она говорит тебе? Страх потери? Ощущение недостаточной значимости? Это информация о твоих потребностях — не команда к действию. Использовать ревность как информацию — значит говорить о потребности а не атаковать партнёра.",
    9: "Понимать как что-то работает — не значит потерять к этому чувство. Образованное переживание богаче необразованного. Знание о любви делает её интереснее а не холоднее. Попробуй читать о том что тебя интересует в сфере отношений — не чтобы починить себя, а из любопытства. Знание о том как работает привязанность, как влияет окситоцин, почему мы выбираем именно этих людей — это не разрушение тайны. Это добавление глубины к тому что уже есть.",
},
532: {
    0: "Если мысли об отношениях занимают больше места чем мысли о себе — стоит спросить: это любовь или это страх потери? Здоровые отношения дают энергию, а не забирают её. Проверь прямо сейчас: сколько времени и энергии занимают мысли об отношениях, партнёре, о том «что он думает», «правильно ли я поступила»? Если это больше чем мысли о собственных интересах, целях, ощущениях — это не любовь как состояние. Это тревожная привязанность которая требует работы.",
    1: "Если замечаешь что снова влюбился в человека который требует работы — стоит остановиться. Притяжение к сложным людям часто не страсть а знакомость травмы. Сделай список: какими были значимые люди в твоей романтической жизни? Есть ли повторяющийся паттерн — эмоциональная недоступность, нестабильность, потребность в спасении? Если да — это не совпадение и не судьба. Это твоя карта любви которая сформировалась в детстве. Её можно перерисовать — но сначала нужно увидеть.",
    2: "Энергия направленная на изменение другого человека — это энергия отнятая у собственного роста. Единственный человек которого ты можешь изменить — это ты. Сколько усилий ты прикладываешь к изменению поведения партнёра — разговорами, намёками, давлением, объяснениями? А сколько — к собственному росту? Перенаправление этой энергии внутрь — один из самых продуктивных сдвигов который возможен в жизни. Не потому что другой не важен. А потому что у тебя реальная власть только над собой.",
    3: "Оценивай человека по тому каков он сейчас — не по тому каким он может стать. Потенциал партнёра не твоя ответственность. «Он станет лучше» — самая дорогостоящая инвестиция в отношениях. Люди меняются когда хотят меняться — не когда кто-то другой верит в их потенциал. Ты можешь любить человека и одновременно видеть что прямо сейчас он не даёт тебе того что тебе нужно. Обе вещи могут быть правдой. И из этой правды можно принять решение.",
    4: "Здоровые отношения добавляют жизнь к твоей жизни — не заменяют её. Следи за тем сохраняешь ли ты себя рядом с партнёром. Есть ли у тебя собственные друзья, интересы, цели — отдельные от партнёра? Есть ли время которое принадлежит только тебе? Если всё это было — и с появлением отношений исчезло, это не признак глубокой любви. Это сигнал слияния которое разрушает обоих. Отдельность не угрожает близости — она её условие.",
    5: "Обращай внимание как тебе физически с человеком. Расслабляешься ли ты рядом с ним или постоянно начеку? Тело — честный индикатор безопасности. Вспомни последнюю встречу с партнёром. Что делало твоё тело — расслаблялось или напрягалось? Спало дыхание или было глубоким? Этот физиологический ответ не лжёт. Он может быть интерпретирован неверно — тревогу иногда принимают за волнение влюблённости. Но со временем тело говорит правду о том безопасно ли тебе рядом с этим человеком.",
    6: "Задай себе вопрос: ты с этим человеком потому что он тебе нравится — или потому что он нуждается в тебе? Это разные основания для отношений. Чувство собственной необходимости — это не то же самое что любовь. Быть нужным может быть очень приятно — особенно если в детстве любовь была условной. Но «он пропадёт без меня» — плохое основание для отношений. Оно создаёт тюрьму для обоих. Здоровые отношения строятся на выборе — не на взаимной зависимости.",
    7: "Признание — не поражение. Пока проблема не названа — она управляет тобой. Когда названа — ты начинаешь управлять ею. Есть ли что-то в твоих паттернах в отношениях что ты знаешь но не хочешь называть? Что-то что мешает снова и снова — но называние которого кажется слишком болезненным или страшным? Именно это и нужно назвать первым. Не потому что это легко. А потому что пока оно не названо — оно определяет твои выборы без твоего ведома.",
    8: "Установить границу — значит уважать и себя и другого. Человек без границ не добрее — он просто не знает где он сам. Есть ли в твоих отношениях что-то что для тебя неприемлемо — но ты не говоришь об этом? Граница не произносимая вслух — не граница. Это накапливаемая обида. Сказать «для меня это неприемлемо» — это не ультиматум и не угроза. Это честная информация которая позволяет другому человеку сделать выбор зная что для тебя важно.",
    9: "Работай над отношениями с собой так же серьёзно как над отношениями с партнёром. Всё что ты ищешь снаружи — начинается внутри. Как ты с собой разговариваешь? Как относишься к своим потребностям? Как реагируешь на свои ошибки? Качество внутренних отношений с собой — это шаблон из которого строятся все внешние отношения. Человек который жесток к себе — притягивает жестокость. Человек который добр к себе — создаёт другое качество связей.",
},
534: {
    0: "Любовь которая причиняет страдание — всё равно воспринимается мозгом как потребность. Это объясняет почему так тяжело уйти даже из плохих отношений. Знание механизма помогает не осуждать себя. Если ты или кто-то близкий не может уйти из болезненных отношений — это не слабость характера. Это биохимия. Мозг буквально испытывает «ломку» при попытке разрыва. Этому нужна поддержка — внешняя структура, помощь близких, иногда терапия. Понимание механизма снимает стыд и открывает путь к реальной помощи.",
    1: "Если чувства к партнёру изменились — это не обязательно конец. Возможно одна система угасла а другие живы. Понимание этого помогает не принимать поспешных решений. Прежде чем принимать решение об отношениях — спроси себя: какие из трёх систем всё ещё активны? Если привязанность и уважение живы — а острая влюблённость ушла, это не кризис. Это нормальная эволюция отношений. Работа над поддержанием системы привязанности и привнесением новизны — это путь.",
    2: "Решения принятые в состоянии острой влюблённости — решения под химическим воздействием. Это не значит что чувства ненастоящие. Важные решения лучше принимать когда острая фаза немного утихла. Если сейчас переживаешь острую влюблённость — дай себе несколько месяцев прежде чем принимать решения о совместной жизни, финансах, переезде. Не потому что чувства неправильные — а потому что твоя оценка рисков и реальности партнёра в этом состоянии существенно искажена. Это биология.",
    3: "Если ты влюбляешься в похожих людей снова и снова — твоя карта любви показывает тебе что-то важное о тебе самом. Стоит изучить её. Что общего у людей в которых ты влюблялся? Какой эмоциональный климат они создавали? Что они вызывали в тебе — безопасность или возбуждение? Знакомость или новизну? Паттерн выбора партнёра — это не случайность. Это карта написанная в детстве. Изучить её — значит получить возможность сделать новый выбор.",
    4: "Боль от разрыва реальна физически. Не нужно говорить себе соберись, это просто отношения. Это биологический процесс — и он требует времени точно так же как заживление раны. Что помогает биологически при переживании разрыва? Социальная поддержка — быть с людьми которые тебя видят. Физическая активность — снижает кортизол. Смена обстановки — снижает триггеры связанные с партнёром. Время — это не клише. Это буквально то сколько нужно мозгу для перестройки.",
    5: "Ревность сигнализирует о том что тебе важно. Вопрос — как ты с ней обращаешься. Импульс — эволюционный. Действие — твой выбор. Следующий раз когда почувствуешь ревность — остановись на секунду. Что именно она говорит тебе? «Мне важны эти отношения», «я боюсь потери», «я не чувствую себя достаточно значимым» — это полезная информация. Поговори об этой потребности — а не об объекте ревности. Ревность как сигнал о потребности — это другой разговор чем ревность как обвинение.",
    6: "Отношения не охлаждаются — они становятся предсказуемыми. Предсказуемость убивает дофамин. Совместные новые опыты — это буквально топливо для влюблённости. Когда вы последний раз делали что-то впервые вместе? Новый ресторан или новая страна — не важно. Важна новизна и совместность. Это не способ «оживить» угасшее — это регулярная практика поддержания живости которая не даёт угаснуть. Маленькие новые опыты раз в неделю стоят дешевле терапии и работают лучше.",
    7: "Желание вернуться к токсичному партнёру после разрыва — это не любовь. Это ломка. Зная это легче не принимать этот импульс за руководство к действию. Если ты переживаешь расставание и чувствуешь непреодолимое желание вернуться — дай этому импульсу 48-72 часа. Не потому что нужно страдать — а потому что острота нейрохимической реакции снижается за это время. Решение принятое через 72 часа качественно отличается от решения принятого в момент пика ломки.",
    8: "Розовые очки — не самообман. Это временная защита пока не выстроилось доверие. Проблема только если они не снимаются никогда. Как долго ты носишь розовые очки в отношениях обычно? Если ты замечаешь очевидные признаки несовместимости уже через год — возможно они были с самого начала но ты их не видел. Это не вина — это защитный механизм. Но знание о нём позволяет в начале отношений намеренно задавать вопросы которые розовые очки предпочли бы не задавать.",
    9: "Отношения которые кажутся угасшими часто просто недополучают топлива. Прежде чем уходить — спроси: когда мы последний раз делали что-то новое вместе? Иногда разговор «мне кажется мы потеряли связь» — это разговор который нужен. Не как претензия — как приглашение. «Я хочу вернуть то что было между нами — и я готов над этим работать» — это очень другой разговор чем «у нас проблемы». Начни с приглашения — и посмотри что случится.",
},
}

count = 0
for b in books:
    bid = b.get("id")
    if bid in updates:
        for i, t in enumerate(b.get("thoughts", [])):
            if i in updates[bid]:
                new_life = updates[bid][i]
                ex = t["example"]
                life_start = ex.find("\n\n**В жизни:**")
                if life_start >= 0:
                    t["example"] = ex[:life_start] + "\n\n**В жизни:** " + new_life
                    count += 1

with open("/root/books/webapp/books.json", "w", encoding="utf-8") as f:
    json.dump(books, f, ensure_ascii=False, separators=(",", ":"))
print(f"Updated {count} thoughts")
